#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> combine(vector<int>& candidates, int target) {
        vector<vector<int>> result;
        vector<int> comb;
        backtrack(result, comb, candidates, target, 0);
        return result;
    }

    void backtrack(vector<vector<int>>& result, vector<int>& comb, vector<int>& candidates, int remain, int start) {
        if (remain == 0) {
            result.push_back(comb);
            return;
        } else if (remain < 0) {
            return;
        }
        for (int i = start; i < candidates.size(); i++) {
            comb.push_back(candidates[i]);
            backtrack(result, comb, candidates, remain - candidates[i], i);
            comb.pop_back();
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> candidates(n);
    for (int i = 0; i < n; i++) cin >> candidates[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    vector<vector<int>> ans = sol.combine(candidates, target);
    cout << ans.size() << endl;
    for (const auto& combination : ans) {
        cout << combination.size() << endl;
        for (int num : combination) {
            cout << num << endl;
        }
    }
    return 0;
}
